#include <bits/stdc++.h>
using namespace std;
const int MAXN = 1005;
int n, m, cnt, ans = -1;
int dx[4] = { 0,1,0,-1 };
int dy[4] = { 1,0,-1,0 };
char mp[MAXN][MAXN];
void count() {
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++) {
            int sx1 = i + dx[0], sx2 = i + dx[1], sx3 = i + dx[2], sx4 = i + dx[3];
            int sy1 = j + dy[0], sy2 = j + dy[1], sy3 = j + dy[2], sy4 = j + dy[3];
            if (mp[i][j] == '.' && mp[sx1][sy1] == '.' && mp[sx2][sy2] == '.' && mp[sx3][sy3] == '.' && mp[sx4][sy4] == '.')
                cnt++;
        }
    }
}
int main() {
    ios::sync_with_stdio(false);
    cin.tie(0);
    cout.tie(0);
    cin >> n >> m;
    for (int i = 0; i <= n + 1; i++) {
    	for (int j = 0; j <= m + 1; j++)
    		mp[i][j] = '.';
	}
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++)
            cin >> mp[i][j];
    }
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++) {
            if (mp[i][j] == '#') {
                cnt = 0;
                mp[i][j] = '.';
                count();
                mp[i][j] = '#';
                ans = max(ans, cnt);
            }
        }
    }
    cout << ans << "\n";
    return 0;
}
